{
  "name": "AI Spark Message Writer",
  "description": "A sophisticated AI-powered writing assistant that helps you craft the perfect message for any occasion—emails, social media, or professional correspondence—using Gemini 3 Flash."
}

import React from 'react';
import ReactDOM from 'react-dom/client';
import App from './App';

const rootElement = document.getElementById('root');
if (!rootElement) {
  throw new Error("Could not find root element to mount to");
}

const root = ReactDOM.createRoot(rootElement);
root.render(
  <React.StrictMode>
    <App />
  </React.StrictMode>
);

export type MessageTone = 'Professional' | 'Friendly' | 'Persuasive' | 'Empathetic' | 'Casual' | 'Urgent';

export type MessagePlatform = 'Email' | 'Slack/Teams' | 'Social Media' | 'SMS' | 'LinkedIn';

export interface WritingState {
  originalText: string;
  refinedText: string;
  tone: MessageTone;
  platform: MessagePlatform;
  isProcessing: boolean;
}

export interface HistoryItem {
  id: string;
  text: string;
  timestamp: number;
}

import { GoogleGenAI } from "@google/genai";
import { MessageTone, MessagePlatform } from "./types";

export class GeminiService {
  private ai: GoogleGenAI;

  constructor() {
    this.ai = new GoogleGenAI({ apiKey: process.env.API_KEY || '' });
  }

  async refineMessage(
    text: string, 
    tone: MessageTone, 
    platform: MessagePlatform
  ): Promise<string> {
    const prompt = `Refine and improve the following message.

    Context:
    - Target Platform: ${platform}
    - Desired Tone: ${tone}
    - Original Message: "${text}"

    Instructions:
    1. Maintain the original core meaning but improve clarity, grammar, and impact.
    2. Adapt the structure to perfectly fit a ${platform} environment.
    3. Ensure the tone is strictly ${tone}.
    4. Provide only the refined text, no preamble or explanation.`;

    try {
      const response = await this.ai.models.generateContent({
        model: 'gemini-3-flash-preview',
        contents: prompt,
        config: {
          temperature: 0.7,
          topP: 0.9,
          topK: 40,
        }
      });

      return response.text || "Failed to generate message. Please try again.";
    } catch (error) {
      console.error("Gemini API Error:", error);
      throw new Error("Communication with AI failed. Ensure your connection is stable.");
    }
  }

  async translateMessage(text: string, targetLanguage: string): Promise<string> {
    const prompt = `Translate the following text into ${targetLanguage}. 
    Text: "${text}"
    Return ONLY the translated text.`;

    try {
      const response = await this.ai.models.generateContent({
        model: 'gemini-3-flash-preview',
        contents: prompt,
      });
      return response.text || text;
    } catch (error) {
      console.error("Translation Error:", error);
      return text;
    }
  }
}

export const geminiService = new GeminiService();

import React, { useState, useEffect, useCallback, useRef } from 'react';
import { 
  Send, 
  RefreshCw, 
  Copy, 
  Check, 
  History, 
  Sparkles, 
  Trash2, 
  Languages, 
  Briefcase, 
  Users, 
  Smile, 
  Heart, 
  Clock, 
  Zap,
  Globe
} from 'lucide-react';
import { MessageTone, MessagePlatform, HistoryItem } from './types';
import { geminiService } from './geminiService';

const TONES: { label: MessageTone; icon: React.ReactNode; color: string }[] = [
  { label: 'Professional', icon: <Briefcase size={16} />, color: 'bg-blue-100 text-blue-700' },
  { label: 'Friendly', icon: <Users size={16} />, color: 'bg-green-100 text-green-700' },
  { label: 'Persuasive', icon: <Zap size={16} />, color: 'bg-purple-100 text-purple-700' },
  { label: 'Empathetic', icon: <Heart size={16} />, color: 'bg-rose-100 text-rose-700' },
  { label: 'Casual', icon: <Smile size={16} />, color: 'bg-amber-100 text-amber-700' },
  { label: 'Urgent', icon: <Clock size={16} />, color: 'bg-red-100 text-red-700' },
];

const PLATFORMS: MessagePlatform[] = ['Email', 'Slack/Teams', 'LinkedIn', 'Social Media', 'SMS'];

const App: React.FC = () => {
  const [originalText, setOriginalText] = useState('');
  const [refinedText, setRefinedText] = useState('');
  const [tone, setTone] = useState<MessageTone>('Professional');
  const [platform, setPlatform] = useState<MessagePlatform>('Email');
  const [isProcessing, setIsProcessing] = useState(false);
  const [isCopied, setIsCopied] = useState(false);
  const [history, setHistory] = useState<HistoryItem[]>([]);
  const [showHistory, setShowHistory] = useState(false);
  const [targetLang, setTargetLang] = useState('Thai');

  // Load history on mount
  useEffect(() => {
    const saved = localStorage.getItem('spark_history');
    if (saved) setHistory(JSON.parse(saved));
  }, []);

  const addToHistory = (text: string) => {
    const newItem: HistoryItem = {
      id: Date.now().toString(),
      text,
      timestamp: Date.now(),
    };
    const updated = [newItem, ...history].slice(0, 20);
    setHistory(updated);
    localStorage.setItem('spark_history', JSON.stringify(updated));
  };

  const handleRefine = async () => {
    if (!originalText.trim()) return;
    setIsProcessing(true);
    try {
      const result = await geminiService.refineMessage(originalText, tone, platform);
      setRefinedText(result);
      addToHistory(result);
    } catch (error) {
      alert(error instanceof Error ? error.message : "Something went wrong");
    } finally {
      setIsProcessing(false);
    }
  };

  const handleTranslate = async () => {
    if (!refinedText && !originalText) return;
    setIsProcessing(true);
    try {
      const textToTranslate = refinedText || originalText;
      const result = await geminiService.translateMessage(textToTranslate, targetLang);
      setRefinedText(result);
    } catch (error) {
      alert("Translation failed");
    } finally {
      setIsProcessing(false);
    }
  };

  const copyToClipboard = () => {
    navigator.clipboard.writeText(refinedText);
    setIsCopied(true);
    setTimeout(() => setIsCopied(false), 2000);
  };

  const clearAll = () => {
    setOriginalText('');
    setRefinedText('');
  };

  return (
    <div className="max-w-6xl mx-auto px-4 py-8 md:py-12">
      {/* Header */}
      <header className="flex flex-col md:flex-row justify-between items-start md:items-center mb-8 gap-4">
        <div>
          <h1 className="text-3xl font-bold text-slate-900 flex items-center gap-2">
            <Sparkles className="text-indigo-600" />
            AI Spark Writer
          </h1>
          <p className="text-slate-500 mt-1">Craft the perfect message with Gemini 3 Flash</p>
        </div>
        <div className="flex items-center gap-3">
          <button 
            onClick={() => setShowHistory(!showHistory)}
            className="flex items-center gap-2 px-4 py-2 bg-white border border-slate-200 rounded-lg text-slate-600 hover:bg-slate-50 transition-colors shadow-sm"
          >
            <History size={18} />
            History
          </button>
          <button 
            onClick={clearAll}
            className="p-2 text-slate-400 hover:text-red-500 transition-colors"
            title="Clear All"
          >
            <Trash2 size={20} />
          </button>
        </div>
      </header>

      <div className="grid grid-cols-1 lg:grid-cols-12 gap-8">
        {/* Main Editor Section */}
        <div className="lg:col-span-8 space-y-6">
          <div className="bg-white rounded-2xl shadow-sm border border-slate-200 overflow-hidden">
            <div className="p-4 border-b border-slate-100 flex items-center justify-between bg-slate-50/50">
              <span className="text-sm font-medium text-slate-500 uppercase tracking-wider">Draft Your Concept</span>
              <div className="flex items-center gap-2">
                <select 
                  value={platform}
                  onChange={(e) => setPlatform(e.target.value as MessagePlatform)}
                  className="text-sm bg-white border border-slate-200 rounded-md px-2 py-1 outline-none focus:ring-2 focus:ring-indigo-500"
                >
                  {PLATFORMS.map(p => <option key={p} value={p}>{p}</option>)}
                </select>
              </div>
            </div>
            <textarea
              value={originalText}
              onChange={(e) => setOriginalText(e.target.value)}
              placeholder="E.g., Tell my boss I'm sick and won't make the meeting, but I'll send the report by tonight."
              className="w-full h-48 p-6 text-lg text-slate-700 placeholder:text-slate-300 resize-none outline-none focus:ring-0"
            />
          </div>

          <div className="flex flex-wrap gap-3 items-center">
            {TONES.map((t) => (
              <button
                key={t.label}
                onClick={() => setTone(t.label)}
                className={`flex items-center gap-2 px-4 py-2 rounded-full text-sm font-medium transition-all ${
                  tone === t.label 
                    ? `${t.color} ring-2 ring-offset-1 ring-indigo-500 shadow-sm scale-105` 
                    : 'bg-white text-slate-500 hover:bg-slate-100 border border-slate-200'
                }`}
              >
                {t.icon}
                {t.label}
              </button>
            ))}
          </div>

          <button
            onClick={handleRefine}
            disabled={isProcessing || !originalText.trim()}
            className="w-full py-4 bg-indigo-600 text-white rounded-xl font-semibold text-lg flex items-center justify-center gap-2 hover:bg-indigo-700 transition-all shadow-lg disabled:bg-slate-300 disabled:cursor-not-allowed group"
          >
            {isProcessing ? (
              <RefreshCw className="animate-spin" />
            ) : (
              <Send size={20} className="group-hover:translate-x-1 transition-transform" />
            )}
            {isProcessing ? 'Thinking...' : 'Spark Perfection'}
          </button>

          {/* Result Section */}
          {(refinedText || isProcessing) && (
            <div className="bg-white rounded-2xl shadow-md border-t-4 border-indigo-500 overflow-hidden animate-in fade-in slide-in-from-bottom-4 duration-500">
              <div className="p-4 border-b border-slate-100 flex items-center justify-between bg-indigo-50/30">
                <span className="text-sm font-semibold text-indigo-700 uppercase tracking-wider flex items-center gap-2">
                  <Sparkles size={16} />
                  Polished Message
                </span>
                <div className="flex items-center gap-2">
                   <div className="flex items-center bg-white border border-slate-200 rounded-lg p-1">
                    <Globe size={14} className="mx-2 text-slate-400" />
                    <input 
                      type="text" 
                      value={targetLang}
                      onChange={(e) => setTargetLang(e.target.value)}
                      className="text-xs w-16 outline-none"
                      placeholder="Lang..."
                    />
                    <button 
                      onClick={handleTranslate}
                      disabled={isProcessing}
                      className="p-1 px-2 text-xs bg-indigo-50 text-indigo-600 rounded hover:bg-indigo-100 transition-colors"
                    >
                      Translate
                    </button>
                  </div>
                  <button 
                    onClick={copyToClipboard}
                    className={`flex items-center gap-1.5 px-3 py-1.5 rounded-lg text-sm font-medium transition-all ${
                      isCopied ? 'bg-green-100 text-green-700' : 'bg-slate-100 text-slate-700 hover:bg-slate-200'
                    }`}
                  >
                    {isCopied ? <Check size={16} /> : <Copy size={16} />}
                    {isCopied ? 'Copied' : 'Copy'}
                  </button>
                </div>
              </div>
              <div className="p-6 text-slate-800 text-lg leading-relaxed whitespace-pre-wrap min-h-[100px]">
                {isProcessing && !refinedText ? (
                  <div className="space-y-3">
                    <div className="h-4 bg-slate-100 rounded w-3/4 animate-pulse"></div>
                    <div className="h-4 bg-slate-100 rounded w-1/2 animate-pulse"></div>
                    <div className="h-4 bg-slate-100 rounded w-5/6 animate-pulse"></div>
                  </div>
                ) : (
                  refinedText
                )}
              </div>
            </div>
          )}
        </div>

        {/* Sidebar / History Section */}
        <div className="lg:col-span-4">
          <div className="sticky top-8 space-y-6">
            <div className="bg-white rounded-2xl p-6 shadow-sm border border-slate-200">
              <h2 className="text-lg font-bold text-slate-900 mb-4 flex items-center gap-2">
                <Languages size={20} className="text-indigo-500" />
                Quick Tips
              </h2>
              <ul className="space-y-4 text-sm text-slate-600">
                <li className="flex gap-3">
                  <div className="bg-indigo-50 text-indigo-600 rounded-full w-6 h-6 flex items-center justify-center shrink-0 font-bold">1</div>
                  <p>Be specific about your goal (e.g., "Request a refund" or "Ask for a promotion").</p>
                </li>
                <li className="flex gap-3">
                  <div className="bg-indigo-50 text-indigo-600 rounded-full w-6 h-6 flex items-center justify-center shrink-0 font-bold">2</div>
                  <p>Mention the recipient's name or relationship for better context.</p>
                </li>
                <li className="flex gap-3">
                  <div className="bg-indigo-50 text-indigo-600 rounded-full w-6 h-6 flex items-center justify-center shrink-0 font-bold">3</div>
                  <p>Switch tones to see how different approaches sound before sending.</p>
                </li>
              </ul>
            </div>

            {/* History List */}
            <div className="bg-white rounded-2xl shadow-sm border border-slate-200 overflow-hidden flex flex-col max-h-[500px]">
              <div className="p-4 border-b border-slate-100 bg-slate-50/50 flex justify-between items-center">
                <h3 className="text-sm font-semibold text-slate-500 uppercase">Recent History</h3>
                <span className="text-xs bg-slate-200 text-slate-600 px-2 py-0.5 rounded-full">{history.length}</span>
              </div>
              <div className="overflow-y-auto custom-scrollbar p-2 space-y-2">
                {history.length === 0 ? (
                  <div className="py-12 text-center text-slate-400">
                    <History size={32} className="mx-auto mb-2 opacity-20" />
                    <p className="text-xs">No history yet</p>
                  </div>
                ) : (
                  history.map((item) => (
                    <div 
                      key={item.id} 
                      className="p-3 rounded-xl border border-slate-100 hover:border-indigo-200 hover:bg-indigo-50/30 transition-all cursor-pointer group"
                      onClick={() => setRefinedText(item.text)}
                    >
                      <p className="text-sm text-slate-700 line-clamp-2 mb-1">{item.text}</p>
                      <span className="text-[10px] text-slate-400 flex items-center gap-1">
                        <Clock size={10} />
                        {new Date(item.timestamp).toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' })}
                      </span>
                    </div>
                  ))
                )}
              </div>
            </div>
          </div>
        </div>
      </div>

      <footer className="mt-16 text-center text-slate-400 text-sm border-t border-slate-200 pt-8 pb-4">
        <p>&copy; {new Date().getFullYear()} AI Spark Writer. Powered by Google Gemini 3 Flash.</p>
      </footer>
    </div>
  );
};

export default App;
